import argparse
import json
import signal
import sys
import threading
import time
import uuid

import pika


RABBITMQ_HOST = "localhost"
RABBITMQ_PORT = 5672
QUEUE_NAME = "task_queue"


def create_connection():
    credentials = None
    params = pika.ConnectionParameters(
        host=RABBITMQ_HOST,
        port=RABBITMQ_PORT,
        credentials=credentials,
        heartbeat=60,
        blocked_connection_timeout=300,
    )
    return pika.BlockingConnection(params)


def declare_queue(channel):
    channel.queue_declare(queue=QUEUE_NAME, durable=True)


def publish_task(task_name, payload=None):
    connection = create_connection()
    channel = connection.channel()
    declare_queue(channel)

    message = {
        "task_id": str(uuid.uuid4()),
        "task_name": task_name,
        "payload": payload or {},
        "created_at": time.time(),
    }

    channel.basic_publish(
        exchange="",
        routing_key=QUEUE_NAME,
        body=json.dumps(message),
        properties=pika.BasicProperties(
            delivery_mode=2,
            content_type="application/json",
        ),
    )
    print(f"Published task: {message['task_id']} ({message['task_name']})")
    connection.close()


class Consumer:
    def __init__(self):
        self.connection = None
        self.channel = None
        self._stopping = threading.Event()

    def connect(self):
        self.connection = create_connection()
        self.channel = self.connection.channel()
        declare_queue(self.channel)
        self.channel.basic_qos(prefetch_count=1)

    def process_task(self, ch, method, properties, body):
        try:
            message = json.loads(body.decode("utf-8"))
            task_id = message.get("task_id")
            task_name = message.get("task_name")
            payload = message.get("payload", {})

            print(f"Received task: {task_id} ({task_name}) payload={payload}")

            duration = payload.get("duration", 1)
            time.sleep(max(0, float(duration)))

            print(f"Completed task: {task_id} ({task_name})")
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            print(f"Failed to process message: {e}", file=sys.stderr)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    def start(self):
        self.connect()
        self.channel.basic_consume(queue=QUEUE_NAME, on_message_callback=self.process_task)
        print(f"Waiting for tasks on queue '{QUEUE_NAME}'. Press Ctrl+C to exit.")
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            self.stop()

    def stop(self):
        if self._stopping.is_set():
            return
        self._stopping.set()
        try:
            if self.channel and self.channel.is_open:
                self.channel.stop_consuming()
        except Exception:
            pass
        try:
            if self.connection and self.connection.is_open:
                self.connection.close()
        except Exception:
            pass
        print("Consumer stopped.")


def parse_payload(payload_text):
    if not payload_text:
        return {}
    try:
        return json.loads(payload_text)
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON payload: {e}")


def main():
    parser = argparse.ArgumentParser(description="RabbitMQ task publisher/consumer using pika")
    subparsers = parser.add_subparsers(dest="command", required=True)

    pub_parser = subparsers.add_parser("publish", help="Publish a task message")
    pub_parser.add_argument("--task", required=True, help="Task name")
    pub_parser.add_argument("--payload", default="{}", help='JSON payload, e.g. \'{"duration":2,"value":"x"}\'')

    subparsers.add_parser("consume", help="Start consuming task messages")

    args = parser.parse_args()

    if args.command == "publish":
        payload = parse_payload(args.payload)
        publish_task(args.task, payload)
    elif args.command == "consume":
        consumer = Consumer()

        def handle_signal(signum, frame):
            consumer.stop()
            sys.exit(0)

        signal.signal(signal.SIGINT, handle_signal)
        signal.signal(signal.SIGTERM, handle_signal)

        consumer.start()


if __name__ == "__main__":
    main()